public class Main {
    public static void main(String[] args) {
        int[] d = {3, 7, 2, 9, 5};
        System.out.println(enBuyuk(d));
    }
    static int enBuyuk(int[] arr) {
        int eb = arr[0];
        for (int s : arr) {
            if (s > eb) eb = s;
        }
        return eb;
    }
}
